 1→/**
 2→ * Seed script for Pipeline and DealStage
 3→ *
 4→ * Creates a default pipeline with 8 stages:
 5→ * new -> qualified -> meeting -> proposal -> negotiation -> contract -> won/lost
 6→ *
 7→ * Run: npx tsx prisma/seed-deals.ts
 8→ */
 9→
10→import { prisma } from '../src/lib/db/prisma';
11→
12→const STAGES = [
13→  { code: 'new', name: 'Новый', order: 1, probability: 10, color: '#94a3b8' },
14→  { code: 'qualified', name: 'Квалифицирован', order: 2, probability: 30, color: '#60a5fa' },
15→  { code: 'meeting', name: 'Встреча назначена', order: 3, probability: 50, color: '#3b82f6' },
16→  { code: 'proposal', name: 'КП отправлено', order: 4, probability: 60, color: '#8b5cf6' },
17→  { code: 'negotiation', name: 'Переговоры', order: 5, probability: 70, color: '#f59e0b' },
18→  { code: 'contract', name: 'Договор', order: 6, probability: 90, color: '#10b981' },
19→  { code: 'won', name: 'Выиграно', order: 7, probability: 100, color: '#22c55e', isWonStage: true },
20→  { code: 'lost', name: 'Проиграно', order: 8, probability: 0, color: '#ef4444', isLostStage: true },
21→];
22→
23→async function seedDeals() {
24→  console.log('Seeding Pipeline and DealStage...');
25→
26→  // Check if default pipeline already exists
27→  const existing = await prisma.pipeline.findUnique({
28→    where: { code: 'default' },
29→  });
30→
31→  if (existing) {
32→    console.log('Default pipeline already exists, skipping seed.');
33→    return;
34→  }
35→
36→  // Create default pipeline
37→  const pipeline = await prisma.pipeline.create({
38→    data: {
39→      id: 'default-pipeline-id',
40→      code: 'default',
41→      name: 'Основная воронка',
42→      description: 'Стандартная воронка продаж',
43→      isActive: true,
44→      createdAt: new Date(),
45→    },
46→  });
47→
48→  console.log(`Created pipeline: ${pipeline.code} - ${pipeline.name}`);
49→
50→  // Create stages
51→  for (const stage of STAGES) {
52→    await prisma.dealStage.create({
53→      data: {
54→        id: `${pipeline.code}-${stage.code}-stage-id`,
55→        pipelineId: pipeline.id,
56→        code: stage.code,
57→        name: stage.name,
58→        order: stage.order,
59→        probability: stage.probability,
60→        color: stage.color,
61→        isWonStage: stage.isWonStage ?? false,
62→        isLostStage: stage.isLostStage ?? false,
63→      },
